pub type BlockingStaticRb<T, const N: usize, X> = BlockingRb<Array<T, N>, X>;

impl<T, const N: usize, X: Semaphore> Default for BlockingRb<Array<T, N>, X> {
    fn default() -> Self {
        BlockingRb::from(SharedRb::default())
    }
}

